-- ============================================
-- SUI Innova GmbH — Datenschutz aktualisiert
-- ============================================
-- Erweitert die bestehende Datenschutzerklaerung um:
-- - Google Analytics (mit Consent-Hinweis)
-- - Google Search Console (kein Tracking)
-- - Cookies-Sektion ueberarbeitet (notwendig vs. statistik)
--
-- Idempotent: ersetzt den text-block-Inhalt der Datenschutz-Seite.
-- ============================================

SET @page_id = (SELECT id FROM pages WHERE slug = 'datenschutz' LIMIT 1);

UPDATE sections
SET content = JSON_SET(
    COALESCE(content, JSON_OBJECT()),
    '$.heading', 'Datenschutzerklärung',
    '$.body',    '<h2>Allgemeines</h2><p>Diese Datenschutzerklärung informiert Sie darüber, welche Daten wir auf unserer Website erheben, zu welchem Zweck wir diese verwenden und welche Rechte Sie diesbezüglich haben. Wir behandeln Ihre persönlichen Daten vertraulich und gemäss dem Schweizer Datenschutzgesetz (DSG) sowie der EU-Datenschutz-Grundverordnung (DSGVO), soweit diese auf uns Anwendung findet.</p><h2>Verantwortliche Stelle</h2><p>Verantwortlich für die Verarbeitung der personenbezogenen Daten auf dieser Website ist:<br><br>SUI Innova GmbH<br>Talstrasse 31<br>8808 Pfäffikon SZ<br>Schweiz<br>info@sui-innova.ch<br>+41 55 420 19 90</p><h2>Server-Logfiles und Besuchsstatistik</h2><p>Beim Aufruf unserer Website werden technisch notwendige Daten verarbeitet (besuchte Seite, Browsertyp, Referrer-URL, anonymisierte IP-Adresse, Zeitpunkt des Zugriffs). Diese Daten werden ausschliesslich zur Sicherstellung des Betriebs und zur statistischen Auswertung verwendet.</p><p>Die IP-Adresse wird vor der Speicherung kryptographisch gehasht und kann nicht zurückgeführt werden. Eine Identifizierung einzelner Besucher ist damit nicht möglich.</p><h2>Kontaktformular</h2><p>Wenn Sie uns über das Kontaktformular eine Nachricht senden, werden die von Ihnen eingegebenen Daten (Name, E-Mail-Adresse, Telefon, Firma, Nachricht) zur Bearbeitung Ihrer Anfrage und für eventuelle Anschlussfragen gespeichert. Diese Daten werden nicht an Dritte weitergegeben.</p><p>Rechtsgrundlage ist Ihre Einwilligung sowie unser berechtigtes Interesse an der Beantwortung Ihrer Anfrage.</p><h2>Bewerbungen</h2><p>Wenn Sie sich über unser Bewerbungsformular bewerben, werden Ihre Angaben (Name, E-Mail, Telefon, Nachricht) sowie die hochgeladenen Dokumente (Lebenslauf, Zeugnisse, etc.) ausschliesslich zur Bearbeitung Ihrer Bewerbung verwendet.</p><p>Wir speichern Ihre Bewerbungsunterlagen für die Dauer des Bewerbungsverfahrens und löschen sie spätestens 6 Monate nach dessen Abschluss, sofern Sie nicht ausdrücklich einer längeren Aufbewahrung für künftige Stellenangebote zustimmen.</p><h2>Cookies</h2><p>Unsere Website verwendet zwei Arten von Cookies:</p><h3>Technisch notwendige Cookies (immer aktiv)</h3><p><strong>Session-Cookie</strong> für eingeloggte Administratoren – wird beim Schliessen des Browsers oder spätestens nach 2 Stunden Inaktivität gelöscht.</p><p><strong>Cookie-Einwilligung</strong> (cookies_accepted) – speichert Ihre Wahl im Cookie-Banner für 365 Tage.</p><h3>Statistik-Cookies (nur mit Ihrer Einwilligung)</h3><p>Diese Cookies werden ausschliesslich gesetzt, wenn Sie im Cookie-Banner die Option <strong>„Alle akzeptieren"</strong> wählen. Bei „Nur notwendige" findet kein Tracking statt.</p><h2>Webanalyse mit Google Analytics</h2><p>Diese Website verwendet Google Analytics 4 (GA4), einen Webanalysedienst der Google Ireland Limited (Gordon House, Barrow Street, Dublin 4, Irland). Google Analytics setzt Cookies (z.B. _ga, _ga_*), die eine anonymisierte Analyse der Benutzung der Website ermöglichen.</p><p>Wir verwenden Google Analytics ausschliesslich mit aktivierter <strong>IP-Anonymisierung</strong>. Ihre IP-Adresse wird vor der Übermittlung an Google in der EU/EWR gekürzt. Eine Zuordnung zu Ihrer Person ist nicht möglich.</p><p>Die Erhebung dieser Daten erfolgt <strong>nur mit Ihrer ausdrücklichen Einwilligung</strong> über unseren Cookie-Banner (Option „Alle akzeptieren"). Sie können Ihre Einwilligung jederzeit widerrufen, indem Sie im Footer auf „Cookie-Einstellungen" klicken oder das Cookie cookies_accepted in Ihrem Browser löschen.</p><p>Mehr Informationen zur Datenverarbeitung durch Google: <a href="https://policies.google.com/privacy" target="_blank" rel="noopener">policies.google.com/privacy</a></p><h2>Google Search Console</h2><p>Wir nutzen die Google Search Console, um zu überwachen, wie unsere Website in der Google-Suche dargestellt wird. Die Verifizierung erfolgt über einen Meta-Tag im HTML-Header der Seite.</p><p>Die Search Console <strong>setzt keine Cookies</strong> und <strong>erhebt keine personenbezogenen Daten</strong> bei Ihrem Besuch. Es werden lediglich technische Informationen über die Indexierung und Suchergebnis-Darstellung an Google übermittelt – ohne Bezug zu einzelnen Besuchern.</p><h2>Hosting</h2><p>Unsere Website wird gehostet bei:<br><br>Hostpoint AG<br>Neue Jonastrasse 60<br>8640 Rapperswil<br>Schweiz</p><p>Sämtliche Daten werden ausschliesslich auf Servern in der Schweiz gespeichert. Es findet keine Datenübermittlung in Drittländer durch unser Hosting statt. (Ausnahme: Google Analytics – siehe oben, nur mit Ihrer Einwilligung.)</p><h2>Weitergabe an Dritte</h2><p>Eine Weitergabe Ihrer persönlichen Daten an Dritte findet grundsätzlich nicht statt, ausser wir sind hierzu gesetzlich verpflichtet oder es ist zur Vertragserfüllung erforderlich.</p><p>Eine Ausnahme bildet Google Analytics: Bei aktivierter Statistik-Einwilligung werden anonymisierte Nutzungsdaten an Google übermittelt (siehe oben).</p><h2>Rechte der betroffenen Personen</h2><p>Sie haben jederzeit das Recht auf:</p><p><strong>Auskunft</strong> über die zu Ihrer Person gespeicherten Daten<br><strong>Berichtigung</strong> unrichtiger Daten<br><strong>Löschung</strong> Ihrer Daten, soweit keine gesetzliche Aufbewahrungspflicht besteht<br><strong>Einschränkung der Verarbeitung</strong><br><strong>Widerspruch</strong> gegen die Verarbeitung<br><strong>Datenübertragbarkeit</strong><br><strong>Widerruf</strong> Ihrer Einwilligung zur Cookie-Nutzung (über „Cookie-Einstellungen" im Footer)</p><p>Bei Fragen oder zur Ausübung Ihrer Rechte wenden Sie sich an: info@sui-innova.ch</p><h2>Datensicherheit</h2><p>Die Übertragung von Daten zwischen Ihrem Browser und unserer Website erfolgt verschlüsselt via HTTPS (TLS). Wir treffen geeignete technische und organisatorische Massnahmen, um Ihre Daten vor unberechtigtem Zugriff, Verlust, Missbrauch oder Manipulation zu schützen.</p><h2>Änderungen dieser Datenschutzerklärung</h2><p>Wir behalten uns vor, diese Datenschutzerklärung jederzeit anzupassen, um sie an geänderte Rechtslagen oder bei Änderungen unserer Dienstleistungen zu aktualisieren. Es gilt jeweils die zum Zeitpunkt Ihres Besuches abrufbare Fassung.</p><h2>Kontakt bei Fragen zum Datenschutz</h2><p>Bei Fragen zur Verarbeitung Ihrer persönlichen Daten oder zu dieser Datenschutzerklärung wenden Sie sich bitte an:<br><br>SUI Innova GmbH<br>Talstrasse 31<br>8808 Pfäffikon SZ<br>info@sui-innova.ch<br>+41 55 420 19 90</p><h2>Stand</h2><p>Diese Datenschutzerklärung wurde zuletzt am 5. Mai 2026 aktualisiert.</p>'
)
WHERE page_id = @page_id AND type = 'text-block';

